  requires m >= 0
  requires ValidScores(a, m)
  ensures Achievable(a, m, score)
  ensures forall v | score < v <= m :: !Achievable(a, m, v)
{
  var s := 0;
  var i := 0;
  while i < |a|
    invariant 0 <= i <= |a|
    invariant s == Sum(a[..i])
  {
    SumAppend(a, i);
    s := s + a[i];
    i := i + 1;
  }

  SumBounds(a, m, |a|);
  assert s == Sum(a);
  if s < m {
    score := s;
  } else {
    score := m;
  }

  assert 0 <= score <= m;
  assert Sum(a) - score >= 0;
  assert Sum(a) - score <= (|a| - 1) * m;
}
